55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const RUNE_BLOCK_PRICE = 60;
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	  moonstone: 25,
65	};
66	
67	const basePremium = (item: Item): number =>
68	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
69	
70	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
71	
72	const groupByType = (items: Item[]): Map<string, Item[]> => {
73	  const groups = new Map<string, Item[]>();
74	  for (const item of items) {
75	    const existing = groups.get(item.type) ?? [];
76	    existing.push(item);
77	    groups.set(item.type, existing);
78	  }
79	  return groups;
80	};
81	
82	const sumBasePremiums = (items: Item[]): number =>
83	  items.reduce((sum, item) => sum + basePremium(item), 0);
84	
85	const groupTotal = (type: string, group: Item[]): number => {
86	  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
87	    return RUNE_BLOCK_PRICE;
88	  }
89	  return sumBasePremiums(group);
90	};
91	
92	const componentsTotal = (items: Item[]): number => {
93	  let total = 0;
94	  for (const [type, group] of groupByType(items)) {
95	    total += groupTotal(type, group);
96	  }
97	  return total;
98	};
99	
100	const quotePremium = (items: Item[]): number =>
101	  componentsTotal(items) + PROCESSING_FEE;
102	
103	export const processScenario = (scenario: Scenario): ScenarioOutput => {
104	  const step = scenario.steps[0] as QuoteStep;
105	  return { results: [{ premium: quotePremium(step.items) }] };
106	};
